const fs = require\('fs'\);
const buf = fs.readFileSync\('/Users/trivo/Development/o1js/src/bindings/compiled/node_bindings/plonk_wasm_bg.wasm'\);

// Parse wasm binary to find memory import
let pos = 8; // skip magic + version
while \(pos < buf.length\) {
  const sectionId = buf[pos++];
  // Read LEB128 size
  let size = 0, shift = 0;
  while \(true\) {
    const byte = buf[pos++];
    size |= \(byte & 0x7f\) << shift;
    if \(!\(byte & 0x80\)\) break;
    shift += 7;
  }
  const sectionEnd = pos + size;

  if \(sectionId === 2\) { // import section
    // Read number of imports
    let count = 0;
    shift = 0;
    while \(true\) {
      const byte = buf[pos++];
      count |= \(byte & 0x7f\) << shift;
      if \(!\(byte & 0x80\)\) break;
      shift += 7;
    }

    for \(let i = 0; i < count; i++\) {
      // Read module name
      let modLen = 0;
      shift = 0;
      while \(true\) {
        const byte = buf[pos++];
        modLen |= \(byte & 0x7f\) << shift;
        if \(!\(byte & 0x80\)\) break;
        shift += 7;
      }
      const modName = buf.subarray\(pos, pos + modLen\).toString\(\);
      pos += modLen;

      // Read field name
      let fieldLen = 0;
      shift = 0;
      while \(true\) {
        const byte = buf[pos++];
        fieldLen |= \(byte & 0x7f\) << shift;
        if \(!\(byte & 0x80\)\) break;
        shift += 7;
      }
      const fieldName = buf.subarray\(pos, pos + fieldLen\).toString\(\);
      pos += fieldLen;

      // Read import kind
      const kind = buf[pos++];

      if \(kind === 2\) { // memory
        const flags = buf[pos++];
        console.log\('Memory import found!'\);
        console.log\('  Module:', modName\);
        console.log\('  Field:', fieldName\);
        console.log\('  Flags byte:', '0x' + flags.toString\(16\)\);
        console.log\('  Has max:', !!\(flags & 0x01\)\);
        console.log\('  Shared:', !!\(flags & 0x02\)\);
        console.log\('  Memory64:', !!\(flags & 0x04\)\);
        break;
      } else if \(kind === 0\) { // function
        // skip type index \(LEB128\)
        while \(buf[pos++] & 0x80\) {}
      } else if \(kind === 3\) { // global
        pos += 2; // type + mutability
      } else if \(kind === 1\) { // table
        pos += 1; // element type
        // skip limits
        const tFlags = buf[pos++];
        while \(buf[pos++] & 0x80\) {} // initial
        if \(tFlags & 1\) while \(buf[pos++] & 0x80\) {} // max
      }
    }
    break;
  }
  pos = sectionEnd;
}
")

