const fs = require\('fs'\);
const buf = fs.readFileSync\('/Users/trivo/Development/o1js/_build/cargo_kimchi_wasm/wasm64-unknown-unknown/release/plonk_wasm.wasm'\);

function readLEB128\(buf, pos, signed = false\) {
  let result = 0n;
  let shift = 0n;
  let byte;
  do {
    byte = buf[pos++];
    result |= BigInt\(byte & 0x7f\) << shift;
    shift += 7n;
  } while \(byte & 0x80\);
  if \(signed && \(byte & 0x40\)\) {
    result |= -\(1n << shift\);
  }
  return [result, pos];
}

let pos = 8;
while \(pos < buf.length\) {
  const sectionId = buf[pos++];
  let [size, newPos] = readLEB128\(buf, pos\);
  pos = Number\(newPos\);
  const sectionEnd = pos + Number\(size\);

  if \(sectionId === 9\) { // element section
    let [count, p] = readLEB128\(buf, pos\);
    pos = Number\(p\);
    console.log\('Element section: count =', Number\(count\)\);

    for \(let i = 0; i < Number\(count\); i++\) {
      const flags = buf[pos++];
      console.log\('  Elem', i, 'flags:', flags\);

      if \(flags === 0x02 || flags === 0x06\) {
        // active with table index
        let [tableIdx, p1] = readLEB128\(buf, pos\);
        pos = Number\(p1\);
        console.log\('  Table index:', Number\(tableIdx\)\);
      }

      // Read offset expression
      const opcode = buf[pos++];
      if \(opcode === 0x41\) { // i32.const
        let [val, p2] = readLEB128\(buf, pos, true\);
        pos = Number\(p2\);
        console.log\('  Offset: i32.const', Number\(val\)\);
      } else if \(opcode === 0x42\) { // i64.const
        let [val, p2] = readLEB128\(buf, pos, true\);
        pos = Number\(p2\);
        console.log\('  Offset: i64.const', val.toString\(\), '\(0x' + val.toString\(16\) + '\)'\);
      } else {
        console.log\('  Unknown opcode:', opcode.toString\(16\)\);
      }
      break; // just check first elem
    }
    break;
  }
  pos = sectionEnd;
}
